sys_script_client.script:
function onLoad() {
    // Only on new records
    if (!g_form.isNewRecord()) return;

    // Get current user's sys_id
    var userID = g_user.userID;

    // Query employee table for matching user
    var gr = new GlideRecord('x_1954179_employ_0_employee');
    gr.addQuery('employee', userID);
    gr.query(function(records) {
        if (records.next()) {
            // Set employee field
            g_form.setValue('employee', 
                records.sys_id.toString(),
                records.getDisplayValue());
            // Lock field so employee can't change it
            if (!g_user.hasRole('x_1954179_employ_0.manager') 
                && !g_user.hasRole('x_1954179_employ_0.admin')) {
                g_form.setReadOnly('employee', true);
            }
        }
    });
}
